lemma SumAppend(s: seq<int>, i: int)
  requires 0 <= i < |s|
  ensures s[..i+1] == s[..i] + [s[i]]
  ensures Sum(s[..i+1]) == Sum(s[..i]) + s[i]
{
  var t := s[..i+1];
  assert t[..|t|-1] == s[..i];
}

lemma SumBounds(a: seq<int>, m: int, k: int)
  requires 0 <= k <= |a|
  requires ValidScores(a, m)
  ensures 0 <= Sum(a[..k]) <= k * m
  decreases k
{
  if k == 0 {
    assert a[..0] == [];
  } else {
    SumBounds(a, m, k - 1);
    SumAppend(a, k - 1);
    assert 0 <= a[k-1] <= m;
  }
}

method GradeAllocation(a: seq<int>, m: int) returns (score: int)
  requires |a| > 0
  requires m >= 0
  requires ValidScores(a, m)
  ensures Achievable(a, m, score)
  ensures forall v | score < v <= m :: !Achievable(a, m, v)
{
  var s := 0;
  var i := 0;
  while i < |a|
    invariant 0 <= i <= |a|
    invariant s == Sum(a[..i])
  {
    SumAppend(a, i);
    s := s + a[i];
    i := i + 1;
  }
  assert 0 <= s <= m * |a|;
  SumBounds(a, m, |a|);
  if s < m {
    score := s;
  } else {
    score := m;
  }
}

